// Define the mapping of keys to their descriptions
const descriptions = {
  "url_cats": "It's point to some unacceptable URLs.",
  "dlp": "It's got sensitive data.",
  "injection": "This contains content that is interperted as trying to do something malicous, please reword your request and try again.",
  "toxic_content": "This contains content that is not in keeping with our policy, please reword your request and try again.",
  "malicious_code": "You are not fooling me with your naughty code.",
  "agent": "Don't mess with my agent.",
  "topic_violation": "We are going off topic.",
  "db_security": "Keep out of DB commands.",
  "ungrounded": "We lost the plot."
};

// Main function to process detections
function processDetections(data) {
    const detectedMessages = ["🛡️ PRISMA AIRS SECURITY ALERT: RESPONSE BLOCKED: "];

    // Combine both detected objects for easier processing
    const allDetections = {
        ...(data.prompt_detected || {}),
        ...(data.response_detected || {})
    };

    // Check each key in the combined detections
    for (const key in allDetections) {
        // If the value is true and a description exists, add it to our list
        if (allDetections[key] === true && descriptions[key]) {
            detectedMessages.push(descriptions[key]);
        }
    }

    // Join the messages with a comma and a space for better readability
    // This RETURN statement is now correctly INSIDE the function
    return detectedMessages.join(' ');
}

// Get the incoming JSON data from the first input item
const item = $input.first().json;

if (item.action == "allow") {
  item.output = $('AI Agent').first().json.output;
} else {
  // Call the function and immediately return its output
  const resultingString = processDetections(item);
  item.output = resultingString;
} 
// Return the modified data
return item;

